  /** Compute this pivot table result. */
  compute(forceRefresh?: boolean | undefined): Promise<PivotTableResult | null>;
  /** Get the full range occupied by the rendered pivot table. */
  getRange(): Promise<WorksheetRange | null>;
  /** Add a field to the row, column, or filter area */
  addField(field: string, area: "column" | "row" | "filter", position?: number | undefined): Promise<PivotHandleMutationReceipt>;
