  /** Change the aggregation function of a value field */
  changeAggregation(valueFieldLabel: string, newAggregation: "min" | "max" | "sum" | "count" | "average"): Promise<PivotHandleMutationReceipt>;
  /** Change the aggregation function of a specific value placement. */
